diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..1c4bc8133a05 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1811,7 +1811,89 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,

   return nullptr;
 }
+static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
+                                                bool IsAnd) {
+  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
+  FCmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  FCmpInst::Predicate Pred1 = Cmp1->getPredicate();
+  // Only handle ordered comparisons for now.
+  if (!FCmpInst::isOrdered(Pred0) || !FCmpInst::isOrdered(Pred1))
+    return nullptr;

+  // Extract the compared value and constant for each cmp.
+  auto GetOperands = [](FCmpInst *Cmp, Value *&X, const APFloat *&C) -> bool {
+    Value *Op0 = Cmp->getOperand(0);
+    Value *Op1 = Cmp->getOperand(1);
+    if (match(Op1, m_APFloat(C))) {
+      X = Op0;
+      return true;
+    }
+    if (match(Op0, m_APFloat(C))) {
+      X = Op1;
+      return true;
+    }
+    return false;
+  };
+
+  Value *X0, *X1;
+  const APFloat *C0, *C1;
+  if (!GetOperands(Cmp0, X0, C0) || !GetOperands(Cmp1, X1, C1))
+    return nullptr;
+  if (X0 != X1)
+    return nullptr;
+
+  // For simplicity, only handle same predicate.
+  if (Pred0 != Pred1)
+    return nullptr;
+
+  // Determine if one range subsumes the other.
+  // Since predicate same, we just compare constants.
+  APFloat::cmpResult Loss = C0->compare(*C1);
+  if (Loss == APFloat::cmpUnordered) // NaN
+    return nullptr;
+
+  // For ordered less than (olt): X < C0, X < C1.
+  // If C0 <= C1, then (X < C0) => (X < C1). So left is stricter.
+  // For AND, take stricter (smaller constant), for OR take larger.
+  // For ordered less or equal (ole): similar.
+  // For greater than: X > C0, X > C1. If C0 >= C1, then (X > C0) => (X > C1).
+  // Need to handle each predicate.
+  bool IsLess = Pred0 == FCmpInst::FCMP_OLT || Pred0 == FCmpInst::FCMP_OLE;
+  bool IsGreater = Pred0 == FCmpInst::FCMP_OGT || Pred0 == FCmpInst::FCMP_OGE;
+  bool IsEqual = Pred0 == FCmpInst::FCMP_OEQ;
+  bool IsNotEqual = Pred0 == FCmpInst::FCMP_ONE;
+  if (!IsLess && !IsGreater && !IsEqual && !IsNotEqual)
+    return nullptr;
+
+  // Determine which constant is "stricter" (implies the other).
+  bool C0Stricter = false;
+  if (IsLess) {
+    // For less, smaller constant is stricter.
+    C0Stricter = Loss == APFloat::cmpLessThan;
+  } else if (IsGreater) {
+    // For greater, larger constant is stricter.
+    C0Stricter = Loss == APFloat::cmpGreaterThan;
+  } else if (IsEqual) {
+    // Equality: only equal constants are same range.
+    if (Loss == APFloat::cmpEqual) {
+      // Both identical, return either.
+      return IsAnd ? Cmp0 : Cmp0;
+    }
+    return nullptr;
+  } else { // IsNotEqual
+    // Not equal: cannot deduce.
+    return nullptr;
+  }
+
+  // If C0 is stricter, then Cmp0 -> Cmp1.
+  // For AND, we need stricter (since both must hold).
+  // For OR, we need looser (since either holds).
+  if (C0Stricter) {
+    return IsAnd ? Cmp0 : Cmp1;
+  } else {
+    return IsAnd ? Cmp1 : Cmp0;
+  }
+}
 static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                                    FCmpInst *RHS, bool IsAnd) {
   Value *LHS0 = LHS->getOperand(0), *LHS1 = LHS->getOperand(1);
@@ -1850,6 +1932,8 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  if (Value *V = simplifyAndOrOfFCmpsWithConstants(LHS, RHS, IsAnd))
+    return V;
   return nullptr;
 }

